SELECT survey_id, survey_name, status
FROM feedback_surveys
WHERE status = 'active';

SELECT question_text, question_type, question_order
FROM feedback_questions
ORDER BY question_order;

SELECT COUNT(*) AS total_active_surveys 
FROM feedback_surveys 
WHERE status = 'active';

SELECT average_rating
FROM feedback_analysis
WHERE question_id = 1;

SELECT question_id, AVG(average_rating) AS average_question_rating
FROM feedback_analysis
GROUP BY question_id;

SELECT COUNT(question_id) 
FROM feedback_questions 
WHERE survey_id = 0;

SELECT question_type, COUNT(*) AS question_count
FROM feedback_questions
GROUP BY question_type;

SELECT question_id, COUNT(*) AS total_responses
FROM feedback_responses
GROUP BY question_id;

SELECT average_rating
FROM feedback_analysis
WHERE question_id = 1;

SELECT DISTINCT fa.survey_id
FROM feedback_analysis fa
WHERE fa.average_rating > 8.0;

SELECT average_rating, total_responses, top_comments
FROM feedback_analysis
WHERE survey_id = 1;
